import React, { useState } from 'react';
import { postAuthAction } from '../utils/api';
import { motion } from 'framer-motion';

function Invite({ user }) {
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [inviteLink, setInviteLink] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setInviteLink('');
    setLoading(true);

    try {
      const response = await postAuthAction('invite_partner', { from_id: user.id, email });

      if (response.data.success) {
        if (response.data.email_sent) {
          setMessage('Invite sent! Your partner should receive an email soon.');
        } else {
          setMessage('Invite created successfully. Email sending is unavailable, so copy the link below and share it manually.');
        }
        const token = response.data.invite?.token;
        if (token) {
          setInviteLink(`${window.location.origin}/accept-invite?token=${encodeURIComponent(token)}`);
        }
        setEmail('');
      } else {
        setError(response.data.error || 'Failed to create invite.');
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Network error. Make sure the backend API is reachable.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 via-white to-lavender-50 px-4 py-10">
      <div className="max-w-3xl mx-auto">
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="bg-white/95 backdrop-blur-xl rounded-[32px] p-10 shadow-2xl border-4 border-pink-200">
          <h1 className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-pink-700 to-purple-700 mb-4">Invite Your Partner 💞</h1>
          <p className="text-gray-700 mb-6">Send a special invite to your partner so they can join your shared memories space.</p>

          {error && <div className="mb-5 rounded-2xl border-l-4 border-red-400 bg-red-50 p-4 text-red-700 font-semibold">{error}</div>}
          {message && <div className="mb-5 rounded-2xl border-l-4 border-green-400 bg-green-50 p-4 text-green-700 font-semibold">{message}</div>}

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="block text-sm font-black text-pink-700 mb-2">Partner email address</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="partner@example.com"
                required
                className="w-full rounded-3xl border-2 border-pink-200 bg-pink-50 px-5 py-3 text-gray-800 focus:border-pink-400 focus:outline-none"
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="inline-flex items-center justify-center rounded-3xl bg-gradient-to-r from-pink-500 via-purple-500 to-fuchsia-500 px-6 py-3 font-black text-white shadow-lg hover:shadow-xl transition disabled:opacity-60"
            >
              {loading ? 'Creating invite...' : 'Send Invite'}
            </button>
          </form>

          {inviteLink && (
            <div className="mt-8 rounded-3xl bg-pink-50 border border-pink-200 p-5">
              <p className="font-bold text-pink-700 mb-3">Manual invite link</p>
              <input
                type="text"
                value={inviteLink}
                readOnly
                className="w-full rounded-2xl border border-pink-300 bg-white px-4 py-3 text-sm text-gray-700"
                onFocus={(e) => e.target.select()}
              />
              <p className="mt-3 text-sm text-gray-600">Copy this link and send it in chat or messenger if email is blocked.</p>
            </div>
          )}

          <div className="mt-10 rounded-3xl bg-gradient-to-br from-white to-pink-50 p-6 border border-pink-200">
            <h2 className="text-xl font-bold text-pink-700 mb-3">How it works</h2>
            <ul className="list-disc list-inside text-gray-700 space-y-2">
              <li>Your partner clicks the invite link and joins the app.</li>
              <li>Once accepted, you are linked as partners in the shared space.</li>
              <li>If email is unavailable, manually share the link above.</li>
            </ul>
          </div>
        </motion.div>
      </div>
    </div>
  );
}

export default Invite;
