import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { postAuthAction } from '../utils/api';
import { motion } from 'framer-motion';

function AcceptInvite({ user }) {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [status, setStatus] = useState('pending');
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const token = searchParams.get('token') || '';

  useEffect(() => {
    if (!token) {
      setError('No invite token found. Please open the invite link sent by your partner.');
      setStatus('error');
    }
  }, [token]);

  const handleAccept = async () => {
    setError('');
    setMessage('');
    setLoading(true);

    try {
      const response = await postAuthAction('accept_invite', { token, user_id: 0 });

      if (response.data.success) {
        setMessage('Your invite has been accepted! You are now connected as partners.');
        setStatus('success');
        setTimeout(() => navigate('/dashboard'), 1800);
      } else {
        setError(response.data.error || 'Unable to accept invite.');
        setStatus('error');
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Network error. Make sure the API is running.');
      setStatus('error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 via-white to-lavender-50 px-4 py-10">
      <div className="max-w-2xl mx-auto">
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="bg-white/95 backdrop-blur-xl rounded-[32px] p-10 shadow-2xl border-4 border-purple-200">
          <h1 className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-purple-700 to-pink-700 mb-4">Accept Partner Invite 💖</h1>
          <p className="text-gray-700 mb-6">Finish connecting with your partner by accepting the invite.</p>

          {error && <div className="mb-5 rounded-2xl border-l-4 border-red-400 bg-red-50 p-4 text-red-700 font-semibold">{error}</div>}
          {message && <div className="mb-5 rounded-2xl border-l-4 border-green-400 bg-green-50 p-4 text-green-700 font-semibold">{message}</div>}

          <div className="mb-6 rounded-3xl bg-pink-50 border border-pink-200 p-5">
            <p className="text-sm text-gray-700">Invite token:</p>
            <p className="font-mono mt-2 break-words text-sm text-gray-800">{token || 'Not available'}</p>
          </div>

          <button
            onClick={handleAccept}
            disabled={loading || !token}
            className="w-full rounded-3xl bg-gradient-to-r from-purple-500 via-pink-500 to-fuchsia-500 px-6 py-3 font-black text-white shadow-lg hover:shadow-xl transition disabled:opacity-60"
          >
            {loading ? 'Accepting invite...' : 'Accept Invite'}
          </button>

          <div className="mt-8 text-sm text-gray-600">
            <p>If you do not have an invite link yet, ask your partner to resend it from the invite page.</p>
          </div>
        </motion.div>
      </div>
    </div>
  );
}

export default AcceptInvite;
